from flask import Flask, request, session
from flask_mfa import MFA

app = Flask(__name__)
app.config["SECRET_KEY"] = "your-secret-key"

# Initialize the MFA module
mfa = MFA(app)

@app.route("/login", methods=["POST"])
def login():
    # Validate the user's credentials
    username = request.form["username"]
    password = request.form["password"]
    if not mfa.verify_credentials(username, password):
        return "Invalid credentials", 401

    # Check if MFA is enabled for this user
    if mfa.is_enabled(username):
        # Prompt the user for an OTP
        otp = request.form["otp"]
        if not mfa.verify_otp(username, otp):
            return "Invalid OTP", 401

    # Grant access to the user
    session["user"] = username
    return "Logged in successfully"

@app.route("/api/direct-login", methods=["POST"])
def direct_login():
    # Validate the user's credentials
    username = request.form["username"]
    password = request.form["password"]
    if not mfa.verify_credentials(username, password):
        return "Invalid credentials", 401

    # Grant access to the user without checking MFA status
    session["user"] = username
    return "Logged in successfully"